3	//  ContactManager
4	//
5	//  The data layer for the contact manager: every create/edit/delete,
6	//  group, and vCard operation goes through here so the views stay thin and
7	//  the logic is unit-testable against an in-memory ModelContext.
8	//
9	//  Each mutating operation runs inside an explicit undo group, saves, and
10	//  rolls back on failure. The group's action name shows up in the Edit menu
11	//  (e.g. "Undo Create Contact") when the context has an UndoManager attached.
12	//
13	
14	import Foundation
15	import SwiftData
16	
17	@MainActor
18	struct ContactStore {
19	    let context: ModelContext
20	
21	    init(_ context: ModelContext) {
22	        self.context = context
23	    }
24	
25	    // MARK: - Contacts
26	
27	    /// Creates an empty contact, optionally adding it to a group.
28	    @discardableResult
29	    func createContact(in group: ContactGroup? = nil) throws -> Contact {
30	        try mutate("Create Contact") {
31	            let contact = Contact()
32	            if let group { contact.groups = [group] }
33	            context.insert(contact)
34	            return contact
35	        }
36	    }
37	
38	    func delete(_ contact: Contact) throws {
39	        try mutate("Delete Contact") {
40	            context.delete(contact)
41	        }
42	    }
43	
44	    func setPhotoData(_ data: Data?, on contact: Contact) throws {
45	        try mutate("Change Photo") {
46	            contact.photoData = data
47	        }
48	    }
49	
50	    // MARK: - Fields (emails / phones)
51	
52	    /// Adds a labeled field, keeping `sortIndex` strictly increasing so order
53	    /// is stable even after deletions.
54	    @discardableResult
55	    func addField(_ kind: FieldKind, value: String = "", to contact: Contact) throws -> ContactField {
56	        try mutate(kind == .email ? "Add Email" : "Add Phone") {
57	            let nextIndex = (contact.fields(of: kind).map(\.sortIndex).max() ?? -1) + 1
58	            let field = ContactField(kind: kind, label: kind.defaultLabel, value: value, sortIndex: nextIndex)
59	            field.contact = contact
60	            context.insert(field)
61	            return field
62	        }
63	    }
64	
65	    func delete(_ fields: [ContactField]) throws {
66	        try mutate("Delete Field") {
67	            fields.forEach(context.delete)
68	        }
69	    }
70	
71	    // MARK: - Groups
72	
73	    @discardableResult
74	    func createGroup(named name: String = "New Group") throws -> ContactGroup {
75	        try mutate("New Group") {
76	            let group = ContactGroup(name: name)
77	            context.insert(group)
78	            return group
79	        }
80	    }
81	
82	    /// Renames a group, ignoring blank names.
83	    func rename(_ group: ContactGroup, to name: String) throws {
84	        let trimmed = name.trimmingCharacters(in: .whitespaces)
85	        guard !trimmed.isEmpty else { return }
86	        try mutate("Rename Group") {
87	            group.name = trimmed
88	        }
89	    }
90	
91	    func delete(_ group: ContactGroup) throws {
92	        try mutate("Delete Group") {
93	            context.delete(group)
94	        }
95	    }
96	
97	    func setMembership(of contact: Contact, in group: ContactGroup, isMember: Bool) throws {
98	        let alreadyMember = contact.groups.contains { $0.persistentModelID == group.persistentModelID }
99	        guard isMember != alreadyMember else { return } // no-op; avoid an unnecessary save
100	
101	        try mutate("Change Group Membership") {
102	            if isMember {
103	                contact.groups.append(group)
104	            } else {
105	                contact.groups.removeAll { $0.persistentModelID == group.persistentModelID }
106	            }
107	        }
108	    }
109	
110	    // MARK: - Merge duplicates
111	
112	    /// Merges several contacts into one canonical contact (the earliest
113	    /// created), then deletes the rest. Empty fields on the canonical contact
114	    /// are filled from the others, emails/phones are unioned and de-duplicated,
115	    /// group memberships are unioned, and a missing photo is adopted.
116	    @discardableResult
117	    func merge(_ contacts: [Contact]) throws -> Contact {
118	        // Earliest created wins, with a stable tiebreaker so the choice is
119	        // deterministic even when timestamps are identical.
120	        let ordered = contacts.sorted { lhs, rhs in
121	            if lhs.createdAt != rhs.createdAt { return lhs.createdAt < rhs.createdAt }
122	            return String(describing: lhs.persistentModelID) < String(describing: rhs.persistentModelID)
123	        }
124	        guard let primary = ordered.first else {
125	            throw ContactStoreError.nothingToMerge
126	        }
127	        let others = ordered.dropFirst()
128	        guard !others.isEmpty else { return primary }
129	
130	        return try mutate("Merge Contacts") {
131	            for other in others {
132	                fillEmptyFields(of: primary, from: other)
133	                adoptGroups(into: primary, from: other)
134	            }
135	            mergeFields(into: primary, from: Array(others))
136	            others.forEach(context.delete)
137	            return primary
138	        }
139	    }
140	
141	    private func fillEmptyFields(of primary: Contact, from other: Contact) {
142	        /// Treat whitespace-only values as empty, consistent with the rest of
143	        /// the codebase (Contact.fullName, primaryEmail, etc.).
144	        func isBlank(_ value: String) -> Bool {
145	            value.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
146	        }
147	        if isBlank(primary.firstName) { primary.firstName = other.firstName }
148	        if isBlank(primary.lastName) { primary.lastName = other.lastName }
149	        if isBlank(primary.company) { primary.company = other.company }
150	        if isBlank(primary.jobTitle) { primary.jobTitle = other.jobTitle }
151	        if isBlank(primary.street) { primary.street = other.street }
152	        if isBlank(primary.city) { primary.city = other.city }
153	        if isBlank(primary.state) { primary.state = other.state }
154	        if isBlank(primary.postalCode) { primary.postalCode = other.postalCode }
155	        if isBlank(primary.country) { primary.country = other.country }
156	        if isBlank(primary.notes) { primary.notes = other.notes }
157	        if primary.birthday == nil { primary.birthday = other.birthday }
158	        if primary.photoData == nil { primary.photoData = other.photoData }
159	    }
160	
161	    private func adoptGroups(into primary: Contact, from other: Contact) {
162	        let existing = Set(primary.groups.map(\.persistentModelID))
163	        for group in other.groups where !existing.contains(group.persistentModelID) {
164	            primary.groups.append(group)
165	        }
166	    }
167	
168	    /// Reassigns every contact's email/phone fields to `primary`, dropping
169	    /// blanks and value-duplicates and reindexing for a stable order.
170	    private func mergeFields(into primary: Contact, from others: [Contact]) {
171	        for kind in FieldKind.allCases {
172	            let candidates = primary.fields(of: kind) + others.flatMap { $0.fields(of: kind) }
173	            var seenValues: Set<String> = []
174	            var keptIndex = 0
175	            for field in candidates {
176	                let normalized = normalizedValue(of: field)
177	                if normalized.isEmpty || seenValues.contains(normalized) {
178	                    context.delete(field)
179	                    continue
180	                }
181	                seenValues.insert(normalized)
182	                field.contact = primary
183	                field.sortIndex = keptIndex
184	                keptIndex += 1
185	            }
186	        }
187	    }
188	
189	    private func normalizedValue(of field: ContactField) -> String {
190	        switch field.kind {
191	        case .email:
192	            field.value.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
193	        case .phone:
194	            String(field.value.filter(\.isNumber))
195	        }
196	    }
197	
198	    // MARK: - vCard import / export
199	
200	    /// Parses a vCard document and inserts the contacts it describes.
201	    @discardableResult
202	    func importVCards(from text: String) throws -> [Contact] {
203	        try importContacts(VCard.parse(text))
204	    }
205	
206	    /// Inserts contacts built from already-parsed vCards. (Parsing can be done
207	    /// off the main actor by the caller; insertion happens here.)
208	    @discardableResult
209	    func importContacts(_ parsed: [ParsedContact]) throws -> [Contact] {
210	        try mutate("Import Contacts") {
211	            let contacts = parsed.map(Self.makeContact(from:))
212	            contacts.forEach(context.insert)
213	            return contacts
214	        }
215	    }
216	
217	    /// Serializes contacts to a vCard document, sorted for stable output.
218	    func exportVCards(_ contacts: [Contact]) -> String {
219	        VCard.makeDocument(from: ContactQuery.sorted(contacts))
220	    }
221	
222	    /// Maps a parsed vCard into a new (uninserted) `Contact` with its fields.
223	    static func makeContact(from parsed: ParsedContact) -> Contact {
224	        let contact = Contact(
225	            firstName: parsed.firstName, lastName: parsed.lastName,
226	            company: parsed.company, jobTitle: parsed.jobTitle,
227	            street: parsed.street, city: parsed.city, state: parsed.state,
228	            postalCode: parsed.postalCode, country: parsed.country,
229	            birthday: parsed.birthday, notes: parsed.notes
230	        )
231	        // Normalize an imported photo through the avatar pipeline so storage
232	        // stays consistent (downscaled JPEG); an undecodable photo is dropped.
233	        if let raw = parsed.photoData {
234	            contact.photoData = ImageProcessing.avatarData(from: raw)
235	        }
236	        let emails = parsed.emails.enumerated().map { index, email in
237	            ContactField(kind: .email, label: email.label, value: email.value, sortIndex: index)
238	        }
239	        let phones = parsed.phones.enumerated().map { index, phone in
240	            ContactField(kind: .phone, label: phone.label, value: phone.value, sortIndex: index)
241	        }
242	        contact.fields = emails + phones
243	        return contact
244	    }
245	
246	    // MARK: - Saving + undo
247	
248	    /// Wraps `body` in an explicit undo group, saves the context, and rolls
249	    /// back on failure. The group is given `actionName` so the Edit menu shows
250	    /// e.g. "Undo Create Contact".
251	    @discardableResult
252	    private func mutate<Result>(_ actionName: String, _ body: () throws -> Result) throws -> Result {
253	        let undoManager = context.undoManager
254	        undoManager?.beginUndoGrouping()
255	        do {
256	            let result = try body()
257	            try context.save()
258	            undoManager?.endUndoGrouping()
259	            undoManager?.setActionName(actionName)
260	            // Observed by ContentView to refresh the Spotlight index. Fired
261	            // after the save commits so observers see the post-mutation state.
262	            NotificationCenter.default.post(name: .contactsDidChange, object: nil)
263	            return result
264	        } catch {
265	            context.rollback()
266	            undoManager?.endUndoGrouping()
267	            throw error
268	        }
269	    }
270	}
271	
272	enum ContactStoreError: LocalizedError {
273	    case nothingToMerge
274	
275	    var errorDescription: String? {
276	        switch self {
277	        case .nothingToMerge: "There were no contacts to merge."
278	        }
279	    }
280	}
281

