292	    private func handleImport(_ result: Result<URL, Error>) {
293	        switch result {
294	        case .failure(let error):
295	            errorMessage = error.localizedDescription
296	        case .success(let url):
297	            Task {
298	                // Read the file and run the avatar pipeline off the main actor
299	                // so a multi-megabyte photo can't hitch the UI.
300	                let avatar: Data? = await Task.detached {
301	                    let didAccess = url.startAccessingSecurityScopedResource()
302	                    defer { if didAccess { url.stopAccessingSecurityScopedResource() } }
303	                    // Decode straight from the file via ImageIO so a huge image
304	                    // is downsampled to a thumbnail without ever loading its
305	                    // full raw bytes into memory (dropping a 300 MB file no
306	                    // longer allocates 300 MB).
307	                    return ImageProcessing.avatarData(from: url)
308	                }.value
309	
310	                guard let avatar else {
311	                    errorMessage = "That file couldn't be read as an image."
312	                    return
313	                }
